        </div>

        {/* Layman Summary */}
        <div className="bg-slate-900/40 border border-slate-800 p-8 rounded-xl relative overflow-hidden">
             <div className="absolute top-0 right-0 p-4 opacity-10 text-slate-500">
                <Lightbulb size={100} />
            </div>
            <h2 className="text-slate-400 font-mono text-sm uppercase tracking-wider mb-3 flex items-center gap-2">
                <Lightbulb size={14} className="text-yellow-500/50" /> Layman's Terms
            </h2>
            <p className="text-base text-gray-400 leading-relaxed italic">
                "{result.laymanSummary}"
            </p>
        </div>

      </div>

      <div className="flex justify-center pt-8">
        <button 
            onClick={reset}
            className="px-8 py-3 bg-white/5 hover:bg-white/10 border border-white/20 rounded-full text-sm font-mono transition-all hover:scale-105"
        >
            ANALYZE ANOTHER PROBLEM
        </button>
      </div>

    </div>
  );
};

export default ResultDisplay;
